import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.example.com/dev")!
        case .staging:
            return URL(string: "https://api.example.com/stage")!
        case .production:
            return URL(string: "https://api.example.com/prod")!
        }
    }
}

class NetworkManager {
    static let shared = NetworkManager()
    
    private init() {}
    
    func fetchUserData(completion: @escaping (Result<UserData, Error>) -> Void) {
        let url = Environment.production.baseURL.appendingPathComponent("users")
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "", code: -1, userInfo: [NSLocalizedDescriptionKey: "No data received"])))
                return
            }
            
            do {
                let userData = try JSONDecoder().decode(UserData.self, from: data)
                completion(.success(userData))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Result<AuthenticationResponse, Error>) -> Void) {
        let url = Environment.production.baseURL.appendingPathComponent("auth")
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let parameters: [String: Any] = [
            "username": username,
            "password": password
        ]
        
        do {
            request.httpBody = try JSONEncoder().encode(parameters)
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "", code: -1, userInfo: [NSLocalizedDescriptionKey: "No data received"])))
                return
            }
            
            do {
                let authenticationResponse = try JSONDecoder().decode(AuthenticationResponse.self, from: data)
                completion(.success(authenticationResponse))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}

struct UserData: Codable {
